import type { CareerQuestion } from "./rrt-questions";

export const ptaQuestionsBatch3: CareerQuestion[] = [
  { id: "pta-1036", stem: "A PTA is applying moist heat to a client's low back before stretching. What is the primary therapeutic effect?", options: ["Decrease tissue temperature", "Increase tissue extensibility, blood flow, and reduce pain/muscle spasm", "Decrease blood flow", "Increase muscle spasm"], correctIndex: 1, rationale: "Moist heat (hydrocollator packs) increases tissue temperature, improving extensibility for stretching, promoting blood flow for healing, and reducing pain and muscle spasm through vasodilation.", difficulty: 1, category: "Therapeutic Exercises", topic: "thermal modalities" },
  { id: "pta-1037", stem: "Which ultrasound parameter produces thermal effects for tissue heating?", options: ["Pulsed 20% duty cycle", "Continuous mode at 1.0-2.0 W/cm²", "Pulsed 10% duty cycle", "No ultrasound produces thermal effects"], correctIndex: 1, rationale: "Continuous ultrasound produces thermal effects: tissue temperature rise increases extensibility. Parameters: 1 MHz for deep tissues, 3 MHz for superficial. Intensity 1.0-2.0 W/cm² for heating.", difficulty: 2, category: "Therapeutic Exercises", topic: "ultrasound parameters" },
  { id: "pta-1038", stem: "A client recovering from ACL reconstruction is at 12 weeks post-surgery. Which exercise progression is appropriate?", options: ["Full return to sport", "Progressive resistive exercises, advanced CKC (lunges, step-ups), agility ladder, light jogging on flat surface", "Only passive ROM", "Maximum effort plyometrics"], correctIndex: 1, rationale: "At 12 weeks post-ACL: PRE, advanced CKC (lunges, step-ups), proprioceptive training, light jogging (if cleared). Return to sport typically occurs at 6-12 months with functional testing.", difficulty: 2, category: "Therapeutic Exercises", topic: "ACL rehabilitation progression" },
  { id: "pta-1039", stem: "What is the primary benefit of neuromuscular electrical stimulation (NMES) for a post-surgical quadriceps?", options: ["Pain reduction only", "Counteract muscle inhibition, prevent atrophy, and facilitate quadriceps activation", "Increase joint flexibility", "Improve cardiovascular endurance"], correctIndex: 1, rationale: "Post-surgical quadriceps inhibition (arthrogenic muscle inhibition) prevents voluntary activation. NMES generates muscle contractions to maintain strength, reduce atrophy, and retrain activation.", difficulty: 2, category: "Therapeutic Exercises", topic: "electrical stimulation" },
  { id: "pta-1040", stem: "A client with adhesive capsulitis is receiving joint mobilization. Which direction of mobilization improves shoulder abduction?", options: ["Anterior glide", "Inferior (caudal) glide", "Posterior glide", "Lateral distraction only"], correctIndex: 1, rationale: "Inferior (caudal) glide of the humeral head improves shoulder abduction. Mobilization direction follows the convex-concave rule: for the convex humeral head, glide is opposite to the restricted motion direction.", difficulty: 3, category: "Therapeutic Exercises", topic: "mobilization techniques" },
  { id: "pta-1041", stem: "Which PNF diagonal pattern combines shoulder flexion, adduction, and external rotation?", options: ["D1 extension", "D1 flexion", "D2 flexion", "D2 extension"], correctIndex: 1, rationale: "D1 flexion: shoulder flexion-adduction-external rotation with forearm supination. D1 mimics functional patterns like combing hair. D2 flexion: flexion-abduction-external rotation.", difficulty: 2, category: "Therapeutic Exercises", topic: "PNF patterns" },
  { id: "pta-1042", stem: "A client needs spinal traction for cervical radiculopathy. What position is MOST commonly used?", options: ["Standing", "Supine with cervical flexion of 20-30° to open the posterior intervertebral foramen", "Prone", "Sidelying"], correctIndex: 1, rationale: "Cervical traction in supine with 20-30° cervical flexion opens the intervertebral foramen, reducing nerve root compression. Force: 10-15% body weight (typically 15-30 lbs) for 15-20 minutes.", difficulty: 2, category: "Therapeutic Exercises", topic: "spinal traction" },
  { id: "pta-1043", stem: "Which exercise is contraindicated for a client with lumbar spinal stenosis?", options: ["Posterior pelvic tilt", "Lumbar extension exercises (prone press-ups)", "Stationary cycling", "Knee-to-chest stretches"], correctIndex: 1, rationale: "Lumbar extension narrows the spinal canal and neural foramen, worsening spinal stenosis symptoms. Flexion-based exercises (Williams) are preferred as they open the spinal canal.", difficulty: 2, category: "Therapeutic Exercises", topic: "spinal stenosis management" },
  { id: "pta-1044", stem: "What is the appropriate ice application time and method for acute injury management?", options: ["1 minute direct to skin", "15-20 minutes with barrier between ice and skin; repeat every 1-2 hours", "60 minutes continuous", "5 seconds only"], correctIndex: 1, rationale: "Cryotherapy: 15-20 minutes with towel/barrier, applied every 1-2 hours during acute phase. Cold causes vasoconstriction, reduced inflammation, decreased pain, and reduced muscle spasm.", difficulty: 1, category: "Therapeutic Exercises", topic: "cryotherapy" },
  { id: "pta-1045", stem: "A client is performing hip abductor strengthening in sidelying. Which muscle is primarily being targeted?", options: ["Adductor longus", "Gluteus medius and gluteus minimus", "Rectus femoris", "Hamstrings"], correctIndex: 1, rationale: "Sidelying hip abduction targets the gluteus medius and minimus. These muscles stabilize the pelvis during single-limb stance and prevent Trendelenburg gait pattern.", difficulty: 1, category: "Therapeutic Exercises", topic: "hip strengthening" },
  { id: "pta-1046", stem: "Which proprioceptive exercise is appropriate for a client in the late phase of ankle sprain rehabilitation?", options: ["Only RICE protocol", "Single-leg stance on an unstable surface (wobble board, BOSU ball) with perturbations", "Strict immobilization", "Only bilateral standing"], correctIndex: 1, rationale: "Late-phase ankle rehab includes advanced proprioception: single-leg stance on unstable surfaces, perturbation training, sport-specific agility, and plyometrics to restore dynamic stability.", difficulty: 2, category: "Therapeutic Exercises", topic: "proprioceptive training" },
  { id: "pta-1047", stem: "What is iontophoresis and when is it used in physical therapy?", options: ["A type of exercise", "Using direct current to drive charged medications (e.g., dexamethasone for inflammation) into tissue transdermally", "A stretching technique", "A gait training method"], correctIndex: 1, rationale: "Iontophoresis uses DC current to deliver charged anti-inflammatory medications (dexamethasone -) or analgesics (lidocaine +) transdermally. Used for tendinitis, bursitis, and local inflammation.", difficulty: 2, category: "Therapeutic Exercises", topic: "iontophoresis" },
  { id: "pta-1048", stem: "A client performing Nordic hamstring exercises is targeting which type of muscle contraction?", options: ["Concentric", "Eccentric (the hamstrings lengthen under load to control forward fall)", "Isometric", "Passive"], correctIndex: 1, rationale: "Nordic hamstring curls eccentrically load the hamstrings: from kneeling, the client slowly lowers forward while the hamstrings control the descent. This reduces hamstring injury risk.", difficulty: 2, category: "Therapeutic Exercises", topic: "eccentric training" },
  { id: "pta-1049", stem: "Which exercise progression is correct for lumbar stabilization?", options: ["Heavy lifting first", "Drawing-in maneuver → bridging → bird-dog → planks → dynamic stability → functional integration", "Plyometrics → stretching → stabilization", "No progression needed"], correctIndex: 1, rationale: "Lumbar stabilization progresses: local stabilizer activation (TrA, multifidus) → static stability (bridge, bird-dog) → dynamic stability (planks, ball exercises) → functional integration.", difficulty: 2, category: "Therapeutic Exercises", topic: "core stabilization progression" },
  { id: "pta-1050", stem: "A PTA is applying phonophoresis. What is this modality?", options: ["Using light to treat tissue", "Using ultrasound to drive topical medications into tissue", "Using electrical stimulation for muscle contraction", "Using magnets for pain relief"], correctIndex: 1, rationale: "Phonophoresis uses ultrasound energy to drive topical medications (hydrocortisone, anti-inflammatories) into tissue through the coupling medium. Parameters similar to therapeutic ultrasound.", difficulty: 2, category: "Therapeutic Exercises", topic: "phonophoresis" },
  { id: "pta-1051", stem: "Which type of TENS provides the strongest analgesic effect but causes visible muscle contraction?", options: ["Conventional TENS (high frequency, low intensity)", "Acupuncture-like TENS (low frequency, high intensity)", "Brief intense TENS", "Burst TENS"], correctIndex: 1, rationale: "Acupuncture-like TENS: low frequency (2-4 Hz), high intensity (to motor threshold causing visible contraction). It stimulates endorphin release for longer-lasting pain relief.", difficulty: 2, category: "Assistive Devices", topic: "TENS parameters" },
  { id: "pta-1052", stem: "A client with foot drop needs an orthotic for community ambulation. Which AFO is MOST functional for an active client?", options: ["Rigid solid-ankle AFO", "Carbon fiber posterior leaf spring AFO", "Metal double upright AFO", "Air cast boot"], correctIndex: 1, rationale: "Carbon fiber PLS AFOs are lightweight, energy-storing, and allow dorsiflexion while preventing foot drop during swing. They are ideal for active community ambulators.", difficulty: 2, category: "Assistive Devices", topic: "dynamic AFOs" },
  { id: "pta-1053", stem: "Which wheelchair cushion is MOST appropriate for a client with SCI who cannot perform weight shifts independently?", options: ["Standard foam cushion", "Low-profile alternating pressure air cushion (ROHO or similar)", "No cushion", "Folded towel"], correctIndex: 1, rationale: "Air-cell cushions (ROHO) distribute pressure through air displacement, providing excellent pressure relief for clients who cannot independently weight-shift. Regular maintenance (inflation check) is required.", difficulty: 2, category: "Assistive Devices", topic: "pressure relief cushions" },
  { id: "pta-1054", stem: "A client with lymphedema of the lower extremity needs compression. What is the recommended application?", options: ["Compression bandaging starting distally (toes) and wrapping proximally with gradient pressure", "Compression starting proximally", "No compression needed", "Tight tourniquet at the thigh"], correctIndex: 0, rationale: "Lymphedema compression: multilayer bandaging starting at the toes, wrapping proximally with decreasing pressure gradient. This promotes lymphatic drainage from distal to proximal.", difficulty: 2, category: "Assistive Devices", topic: "compression therapy" },
  { id: "pta-1055", stem: "Which assistive device enables a client with lower extremity weakness to stand from a standard-height chair?", options: ["Wheelchair only", "Raised seat cushion or chair riser plus armrest pushups", "No devices available", "Ankle weights"], correctIndex: 1, rationale: "Raised seat cushions, chair risers, or higher chairs reduce the demand on knee extensors and hip extensors during sit-to-stand. Armrests provide UE assistance for rising.", difficulty: 1, category: "Assistive Devices", topic: "sit-to-stand aids" },
  { id: "pta-1056", stem: "A client with a transtibial prosthesis has excessive knee flexion during stance phase. What is the likely cause?", options: ["Foot too large", "Socket aligned in excessive flexion or foot positioned too far posterior", "Normal prosthetic gait", "Socket too loose"], correctIndex: 1, rationale: "Excessive knee flexion during stance suggests the socket is in too much flexion or the foot is set too far posteriorly, shifting the ground reaction force anterior to the knee.", difficulty: 3, category: "Assistive Devices", topic: "prosthetic alignment" },
  { id: "pta-1057", stem: "Which type of knee brace unloads the medial compartment for a client with medial knee osteoarthritis?", options: ["Prophylactic knee brace", "Valgus unloader brace (applies valgus force to open the medial compartment)", "Neoprene sleeve", "Patellofemoral brace"], correctIndex: 1, rationale: "A valgus unloader brace applies a 3-point force system creating valgus moment at the knee, opening the medial compartment and reducing bone-on-bone compression in medial OA.", difficulty: 2, category: "Assistive Devices", topic: "knee bracing for OA" },
  { id: "pta-1058", stem: "A client who cannot grip crutch handles due to hand weakness should use which type of crutch?", options: ["Standard axillary crutches", "Platform (forearm trough) crutches that support the forearm without requiring grip", "No crutches available", "Walking poles"], correctIndex: 1, rationale: "Platform crutches have a forearm trough that supports the forearm, distributing weight through the forearm without requiring hand grip. Used for clients with RA, hand weakness, or fractures.", difficulty: 1, category: "Assistive Devices", topic: "crutch adaptations" },
  { id: "pta-1059", stem: "Which type of electrical stimulation is used for wound healing by promoting circulation and cellular activity?", options: ["TENS", "High-voltage pulsed current (HVPC) for wound healing", "Iontophoresis", "Russian stimulation"], correctIndex: 1, rationale: "HVPC promotes wound healing through increased blood flow, bacterial inhibition, and enhanced cellular migration. Negative polarity for infected wounds (bactericidal), positive for clean wounds (epithelialization).", difficulty: 2, category: "Assistive Devices", topic: "electrotherapy for wounds" },
  { id: "pta-1060", stem: "A client with cervical radiculopathy benefits from which cervical orthosis?", options: ["Lumbosacral corset", "Philadelphia collar or cervical collar providing support and limiting motion", "Ankle brace", "Wrist splint"], correctIndex: 1, rationale: "Cervical collars (Philadelphia, Aspen) support the cervical spine, limit motion, and reduce loading on irritated nerve roots. Used during acute cervical radiculopathy.", difficulty: 1, category: "Assistive Devices", topic: "cervical orthoses" },
  { id: "pta-1061", stem: "A client shows signs of skin maceration under a compression bandage. What should the PTA do?", options: ["Continue bandaging without changes", "Remove the bandage, allow the skin to dry, apply skin barrier, reassess bandaging technique", "Apply more layers", "Ignore the maceration"], correctIndex: 1, rationale: "Skin maceration under compression indicates excessive moisture. Remove the bandage, clean and dry the skin, apply skin barrier or moisture barrier, and reassess wrapping technique.", difficulty: 1, category: "Patient Safety", topic: "compression safety" },
  { id: "pta-1062", stem: "What are the absolute contraindications for therapeutic ultrasound?", options: ["Mild muscle soreness", "Over malignant tumors, over the pregnant uterus, over the eyes, over areas with thrombophlebitis, and over the spinal cord post-laminectomy", "Chronic tendinitis", "Joint stiffness"], correctIndex: 1, rationale: "Absolute US contraindications: malignancy, pregnant uterus, eyes, acute thrombophlebitis, over the heart, over growth plates in children, and active hemorrhage.", difficulty: 2, category: "Patient Safety", topic: "ultrasound contraindications" },
  { id: "pta-1063", stem: "A client reports increasing pain (8/10) during exercise that was previously 3/10. What should the PTA do?", options: ["Push through the pain", "Stop the exercise, reassess, document the change, and notify the supervising PT", "Increase the exercise intensity", "Ignore pain reports"], correctIndex: 1, rationale: "Significant pain increase during exercise requires stopping, reassessing, and notifying the PT. Pain escalation may indicate tissue damage, exacerbation, or need for plan modification.", difficulty: 1, category: "Patient Safety", topic: "pain monitoring" },
  { id: "pta-1064", stem: "Which clinical sign indicates that a wound may be infected and requires medical attention?", options: ["Mild pink coloring at wound edges", "Increasing redness, warmth, purulent drainage, foul odor, and fever", "Dry wound bed", "Slight serous drainage"], correctIndex: 1, rationale: "Wound infection signs: increasing erythema (redness), warmth, purulent (pus) drainage, foul odor, fever, and increasing pain. Report immediately for medical evaluation and possible antibiotics.", difficulty: 1, category: "Patient Safety", topic: "wound infection signs" },
  { id: "pta-1065", stem: "A client with a pacemaker should avoid which PT modality?", options: ["Ice packs", "Shortwave diathermy and therapeutic ultrasound near the device", "AROM exercises", "Gait training"], correctIndex: 1, rationale: "Shortwave and microwave diathermy are absolutely contraindicated with pacemakers/ICDs. Therapeutic ultrasound should not be applied near the device. TENS requires caution.", difficulty: 2, category: "Patient Safety", topic: "pacemaker precautions" },
  { id: "pta-1066", stem: "When transferring a client, at what point should the PTA abort the transfer?", options: ["Never — always complete the transfer", "When the client shows signs of distress, loss of balance that cannot be controlled, or the client requests to stop", "Only if equipment breaks", "Only if asked by a supervisor"], correctIndex: 1, rationale: "Abort transfers when: the client shows distress (pain, dizziness, fear), balance is lost beyond the PTA's ability to control, the client requests stopping, or safety is compromised.", difficulty: 1, category: "Patient Safety", topic: "transfer safety" },
  { id: "pta-1067", stem: "A PTA notices a client's skin turning white and numb under an ice pack. What should be done?", options: ["Continue the ice application", "Remove the ice immediately — these are signs of tissue damage/frostbite (blanching, numbness)", "Apply more ice", "Add heat on top of the ice"], correctIndex: 1, rationale: "Skin blanching (white color) and numbness during cryotherapy indicate risk of frostbite or cold injury. Remove ice immediately, warm the area gently, and document the response.", difficulty: 1, category: "Patient Safety", topic: "cryotherapy safety" },
  { id: "pta-1068", stem: "Which safety measure is MOST important when a client is using a treadmill during physical therapy?", options: ["No safety measures needed", "Attach the emergency stop clip to the client and have the client straddle the belt before starting", "Leave the client unattended", "Start at maximum speed"], correctIndex: 1, rationale: "Treadmill safety: attach emergency stop clip, have client straddle the belt before starting, begin at low speed, maintain handrail contact initially, and stay within reach for assistance.", difficulty: 1, category: "Patient Safety", topic: "equipment safety" },
  { id: "pta-1069", stem: "A client has a known history of seizures. What precaution should the PTA take during therapy?", options: ["No special precautions", "Have the client exercise in a safe environment, know seizure protocol, keep timing device nearby, and clear dangerous objects", "Restrain the client during therapy", "Only see the client when medication has been adjusted"], correctIndex: 1, rationale: "Seizure precautions: safe environment (padded mat areas), know seizure protocol, time seizures, clear dangerous objects, don't restrain, turn to side post-seizure, and call for help if prolonged.", difficulty: 1, category: "Patient Safety", topic: "seizure precautions" },
  { id: "pta-1070", stem: "Which sign indicates that a compression wrap is applied too tightly?", options: ["Comfortable snug fit", "Distal numbness, tingling, cyanosis (blue discoloration), or increased pain", "Mild warmth", "No signs — always safe"], correctIndex: 1, rationale: "Too-tight compression signs: distal numbness/tingling, cyanosis (blue color), cold skin, increased pain, and absent pulses. Check CMS (circulation, movement, sensation) after application.", difficulty: 1, category: "Patient Safety", topic: "compression safety" },
  { id: "pta-1071", stem: "What is the proper sequence for removing PPE after treating an isolation patient?", options: ["Mask → gown → gloves → goggles", "Gloves → goggles/face shield → gown → mask/respirator (outside room)", "Any order is fine", "Keep PPE on after leaving the room"], correctIndex: 1, rationale: "Doffing order: gloves first (most contaminated), then goggles/face shield, then gown, then mask/respirator (removed outside the room). Hand hygiene after each step.", difficulty: 1, category: "Infection Prevention", topic: "PPE removal sequence" },
  { id: "pta-1072", stem: "A client with C. difficile infection requires which specific hand hygiene method?", options: ["Alcohol-based hand rub only", "Soap and water handwashing (C. diff spores are resistant to alcohol-based hand rubs)", "No hand hygiene needed", "Water only"], correctIndex: 1, rationale: "C. diff spores are not killed by alcohol-based sanitizers. Soap and water physically remove spores from hands. Bleach-based environmental disinfection is also required.", difficulty: 2, category: "Infection Prevention", topic: "C. diff precautions" },
  { id: "pta-1073", stem: "When should a PTA change gloves during treatment?", options: ["Once per day", "Between dirty and clean tasks on the same patient, after touching contaminated surfaces, and between each patient", "Only when visibly soiled", "Never change during a treatment session"], correctIndex: 1, rationale: "Glove changes: between dirty/clean body sites on the same patient, after touching contaminated items, between patients, and when gloves are torn or contaminated.", difficulty: 1, category: "Infection Prevention", topic: "glove use" },
  { id: "pta-1074", stem: "A client is on droplet precautions for influenza. What PPE does the PTA need?", options: ["N95 respirator", "Surgical mask when within 6 feet of the client", "Full hazmat suit", "No mask needed"], correctIndex: 1, rationale: "Droplet precautions require a surgical/procedure mask within 6 feet of the client. Droplets are larger particles that don't remain airborne, so N95 is not required.", difficulty: 1, category: "Infection Prevention", topic: "droplet precautions" },
  { id: "pta-1075", stem: "How should hydrotherapy equipment (whirlpools) be disinfected between patients?", options: ["Rinse with water only", "Drain, clean with facility-approved disinfectant, and allow proper contact time before next use", "No cleaning needed", "Clean weekly only"], correctIndex: 1, rationale: "Hydrotherapy equipment must be drained, thoroughly cleaned with approved disinfectant (with adequate contact time), rinsed, and dried between patients to prevent cross-contamination.", difficulty: 1, category: "Infection Prevention", topic: "hydrotherapy infection control" },
  { id: "pta-1076", stem: "In PT documentation, which is an example of an objective measurement?", options: ["The client says they feel better", "Right knee AROM: 5-95° flexion measured with goniometer", "The client seems motivated", "Family thinks progress is good"], correctIndex: 1, rationale: "Objective data includes measurable findings: ROM with instrument, strength grades, gait distance, timed assessments, and standardized test scores. Subjective data is the client's self-report.", difficulty: 1, category: "Documentation", topic: "objective documentation" },
  { id: "pta-1077", stem: "What documentation is required to justify continued PT services to Medicare?", options: ["Only the initial evaluation", "Ongoing progress notes showing skilled intervention, measurable progress toward functional goals, and medical necessity", "A note saying the client likes therapy", "Only billing records"], correctIndex: 1, rationale: "Medicare requires documentation of skilled PT services, measurable functional progress, medical necessity, and justification for continued services. Without this, services may be denied.", difficulty: 1, category: "Documentation", topic: "Medicare documentation" },
  { id: "pta-1078", stem: "Which abbreviation indicates non-weight-bearing status?", options: ["WBAT", "NWB", "PWB", "FWB"], correctIndex: 1, rationale: "NWB = Non-Weight-Bearing (no weight through the extremity). Other WB status: TTWB (toe-touch), PWB (partial), WBAT (as tolerated), FWB (full weight-bearing).", difficulty: 1, category: "Documentation", topic: "clinical abbreviations" },
  { id: "pta-1079", stem: "When making a documentation error, the PTA should:", options: ["Use white-out to cover the mistake", "Draw a single line through the error, write 'error,' initial, date, and write the correct information", "Tear out the page and rewrite", "Leave the error and continue"], correctIndex: 1, rationale: "Legal documentation correction: single line through error, write 'error' (or 'late entry'), initial, date, and write correct information. Never erase, white-out, or destroy records.", difficulty: 1, category: "Documentation", topic: "error correction" },
  { id: "pta-1080", stem: "A PTA documents 'Client ambulated 200ft with RW, mod A x1, 2 verbal cues for posture.' This is an example of which documentation element?", options: ["Subjective", "Objective (measurable functional performance data)", "Assessment", "Plan"], correctIndex: 1, rationale: "This is objective documentation: specific distance (200ft), device (RW=rolling walker), assist level (mod A x1), and additional information (2 verbal cues for posture). All measurable.", difficulty: 1, category: "Documentation", topic: "functional documentation" },
  { id: "pta-1081", stem: "A PTA is treating a client with chronic low back pain who has catastrophizing thoughts about their condition. Which approach is MOST appropriate?", options: ["Ignore the psychological component", "Provide pain neuroscience education, grade activity exposure, and set realistic functional goals", "Tell the client their pain is not real", "Only treat with passive modalities"], correctIndex: 1, rationale: "Pain catastrophizing is addressed through pain neuroscience education (explain pain mechanisms), graded activity exposure, cognitive reframing of pain beliefs, and functional goal-setting.", difficulty: 2, category: "Professional Ethics", topic: "psychologically-informed practice" },
  { id: "pta-1082", stem: "A client asks the PTA to perform spinal manipulation. What should the PTA do?", options: ["Perform the manipulation", "Explain that spinal manipulation is outside the PTA's scope of practice and refer to the PT", "Attempt the technique anyway", "Tell the client manipulation is not useful"], correctIndex: 1, rationale: "Spinal manipulation is outside the PTA's scope of practice (it requires the clinical decision-making of the PT). The PTA should explain scope limitations and refer to the supervising PT.", difficulty: 1, category: "Professional Ethics", topic: "scope of practice" },
  { id: "pta-1083", stem: "A PTA witnesses another staff member using improper body mechanics during a transfer, putting a client at risk. What should the PTA do?", options: ["Ignore it — not their responsibility", "Intervene to ensure client safety, then report the concern to the supervisor", "Join in the improper technique", "Wait until the transfer is complete, then do nothing"], correctIndex: 1, rationale: "Patient safety is the highest priority. The PTA should intervene to protect the client, then report the concern to the supervisor for corrective action and staff education.", difficulty: 1, category: "Professional Ethics", topic: "patient advocacy" },
  { id: "pta-1084", stem: "According to the APTA Code of Ethics, which principle requires the PTA to provide competent care?", options: ["Autonomy", "Justice", "Integrity — acting with competence and maintaining professional development", "Beneficence"], correctIndex: 2, rationale: "Integrity requires PTAs to practice with competence, maintaining knowledge through continuing education, practicing within scope, and being honest in all professional interactions.", difficulty: 1, category: "Professional Ethics", topic: "APTA ethics" },
  { id: "pta-1085", stem: "A client shares personal information unrelated to treatment. What is the PTA's obligation?", options: ["Share it with colleagues for entertainment", "Maintain confidentiality — personal information shared during treatment is protected health information", "Post it on social media", "Share it with the client's family"], correctIndex: 1, rationale: "All client information shared during treatment is confidential under HIPAA. The PTA must maintain confidentiality and only share relevant clinical information with the treatment team.", difficulty: 1, category: "Professional Ethics", topic: "confidentiality" },
  { id: "pta-1086", stem: "When communicating with a client who uses a wheelchair, what is the BEST practice?", options: ["Stand over the client and talk down to them", "Sit or kneel to eye level when having a conversation, and speak directly to the client", "Talk to the client's caregiver instead", "Shout so the client can hear"], correctIndex: 1, rationale: "Communicate at eye level, speak directly to the client (not their caregiver), use person-first language, and respect their autonomy and independence.", difficulty: 1, category: "Patient Communication", topic: "disability communication" },
  { id: "pta-1087", stem: "A client is frustrated with slow progress and says 'I'll never walk again.' How should the PTA respond?", options: ["Agree with the client", "Acknowledge their frustration, validate feelings, review actual progress made, and refocus on achievable goals", "Tell them to stop complaining", "Ignore the statement"], correctIndex: 1, rationale: "Therapeutic response: validate emotions, acknowledge frustration, provide objective evidence of progress (data), and collaboratively set realistic, achievable short-term goals to build confidence.", difficulty: 1, category: "Patient Communication", topic: "therapeutic communication" },
  { id: "pta-1088", stem: "Which communication strategy is MOST effective when instructing an elderly client with hearing loss?", options: ["Shout from across the room", "Face the client, speak clearly (not excessively loud), reduce background noise, and use visual demonstrations", "Whisper", "Use only written instructions"], correctIndex: 1, rationale: "Hearing loss communication: face the client (lip reading), clear speech at moderate volume, reduce background noise, supplement with visual demonstrations, and confirm understanding.", difficulty: 1, category: "Patient Communication", topic: "hearing impairment communication" },
  { id: "pta-1089", stem: "A PTA needs to communicate a change in the client's status to the PT. Which communication method is recommended?", options: ["Wait until the next scheduled meeting", "Use direct verbal communication plus written documentation (SBAR format) for timely and accurate reporting", "Text message only", "Leave a sticky note"], correctIndex: 1, rationale: "SBAR (Situation, Background, Assessment, Recommendation) provides structured communication: what's happening, background context, your assessment, and what you recommend. Document the communication.", difficulty: 1, category: "Patient Communication", topic: "interprofessional communication" },
  { id: "pta-1090", stem: "When educating a client about their home exercise program, which approach maximizes adherence?", options: ["Give a 20-page handout", "Keep it simple (3-5 exercises), demonstrate each one, have the client perform a return demonstration, and relate exercises to personal goals", "Only verbal instructions", "Give maximum exercises possible"], correctIndex: 1, rationale: "HEP adherence: limit to 3-5 exercises, demonstrate, return demonstration, provide clear written/visual handout, relate to personal goals, and follow up on compliance.", difficulty: 1, category: "Patient Communication", topic: "patient education" },
  { id: "pta-1091", stem: "The PT asks the PTA to co-treat a complex patient with the OT. What is the PTA's role in interdisciplinary collaboration?", options: ["Refuse to collaborate", "Share relevant observations, coordinate treatment goals, communicate progress, and integrate PT objectives with OT plan", "Take over OT's role", "Only observe"], correctIndex: 1, rationale: "Interdisciplinary collaboration: share information about the client's mobility/function, coordinate complementary goals, communicate progress, and integrate PT objectives with other disciplines.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "co-treatment" },
  { id: "pta-1092", stem: "The physician changes a client's weight-bearing status from NWB to PWB. What should the PTA do?", options: ["Continue NWB status", "Verify the order, update the PT, adjust treatment activities to incorporate PWB, and document the change", "Change to FWB immediately", "Ignore the order"], correctIndex: 1, rationale: "The PTA must verify physician orders, communicate with the supervising PT, adjust treatment to reflect new WB status, educate the client, and document the order change.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "order changes" },
  { id: "pta-1093", stem: "The nursing staff reports that a client has had two falls during the night. How does this affect the PTA's treatment plan?", options: ["No effect on PT", "Modify treatment to address fall risk: assess contributing factors, review balance/strength, implement fall prevention strategies", "Cancel all PT sessions", "Blame nursing for the falls"], correctIndex: 1, rationale: "Falls inform PT care: assess contributing factors (medications, environment, weakness), modify treatment to address deficits, implement fall prevention education, and communicate with the team.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "nursing-PT collaboration" },
  { id: "pta-1094", stem: "Which team member should the PTA consult when a client needs a custom wheelchair?", options: ["Only the PT", "The PT, a certified rehabilitation technology supplier (RTS)/assistive technology professional (ATP), and the client", "The nurse only", "No consultation needed"], correctIndex: 1, rationale: "Custom wheelchair prescription requires: PT (functional assessment), ATP/RTS (technology expertise, fitting), the client (preferences, lifestyle), and potentially the physician for authorization.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "wheelchair team" },
  { id: "pta-1095", stem: "The social worker informs the PTA that the client will be discharged to a skilled nursing facility. How does this affect PT discharge planning?", options: ["No effect", "Adjust discharge goals and recommendations to the SNF setting, prepare transfer summary, and communicate ongoing PT needs", "Stop all treatment immediately", "Only focus on home discharge"], correctIndex: 1, rationale: "Discharge to SNF affects goals: ensure functional mobility for SNF environment, prepare detailed transfer summary with current status, goals, and recommendations for continuing PT.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "discharge planning" },
  { id: "pta-1096", stem: "A 70-year-old client post-stroke has difficulty with dressing, feeding, and community mobility. Which team approach addresses all these areas?", options: ["PT only", "Interdisciplinary approach: PT (mobility), OT (ADLs, UE function), SLP (communication/swallowing), social work (resources), nursing (medical management)", "OT only", "Social work only"], correctIndex: 1, rationale: "Post-stroke rehabilitation requires an interdisciplinary team addressing all functional domains: mobility (PT), ADLs and UE function (OT), communication/swallowing (SLP), psychosocial (SW), and medical (nursing/physician).", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "stroke team" },
  { id: "pta-1097", stem: "A client with diabetes presents with a non-healing wound on the plantar surface of the foot. The PTA should consult which specialist?", options: ["Only the PT", "Wound care specialist and/or podiatrist in addition to the PT", "Cardiologist", "Ophthalmologist"], correctIndex: 1, rationale: "Diabetic foot wounds require wound care specialist/podiatrist input for debridement, off-loading, vascular assessment, and infection management in addition to PT interventions.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "wound care referral" },
  { id: "pta-1098", stem: "A client 3 days post-TKR demonstrates sudden onset of calf swelling, warmth, and pain. Which clinical scenario should the PTA be most concerned about?", options: ["Normal post-surgical swelling", "Deep vein thrombosis (DVT) — stop exercise, keep the client still, and notify the PT/physician immediately", "Muscle strain from exercise", "Allergic reaction"], correctIndex: 1, rationale: "Post-surgical unilateral calf swelling, warmth, and pain are classic DVT signs. DVT is a medical emergency due to pulmonary embolism risk. Stop all activity and get immediate medical evaluation.", difficulty: 2, category: "Clinical Case Scenarios", topic: "post-surgical DVT" },
  { id: "pta-1099", stem: "A client with Parkinson's disease is having difficulty with freezing of gait. Which strategy has the BEST evidence?", options: ["Walk faster", "External rhythmic auditory cues (metronome or music with a beat) and visual cues (laser pointer or floor lines)", "No effective strategies exist", "Medication only"], correctIndex: 1, rationale: "External cues bypass the defective basal ganglia: rhythmic auditory cues (metronome, music) set the pace, visual cues (laser pointer, floor lines) initiate stepping. Both reduce freezing episodes.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Parkinson's gait strategies" },
  { id: "pta-1100", stem: "A 35-year-old runner presents with anterior knee pain that worsens with stair descent and prolonged sitting. What is the likely diagnosis and appropriate treatment?", options: ["ACL tear — surgery referral", "Patellofemoral pain syndrome — VMO strengthening, hip strengthening, patellar taping, and activity modification", "Meniscal tear — arthroscopy", "IT band syndrome — lateral stretching only"], correctIndex: 1, rationale: "Patellofemoral pain syndrome: anterior knee pain worsened by stairs, prolonged sitting ('theater sign'), squatting. Treatment: VMO and hip strengthening, patellar taping/bracing, flexibility, and biomechanical correction.", difficulty: 2, category: "Clinical Case Scenarios", topic: "patellofemoral pain" },
  { id: "pta-1101", stem: "A client with a transtibial amputation is 3 weeks post-surgery. Which interventions are appropriate at this stage?", options: ["Immediate prosthetic fitting and running", "Desensitization, residual limb shaping (elastic wrap), ROM maintenance, strengthening, and transfer training", "No intervention until 12 weeks", "Only wound care"], correctIndex: 1, rationale: "3 weeks post-amputation: wound care, desensitization, shrinkage/shaping (elastic wrap/shrinker sock), maintaining knee extension ROM, strengthening, transfers, and pre-prosthetic training.", difficulty: 2, category: "Clinical Case Scenarios", topic: "amputee pre-prosthetic training" },
  { id: "pta-1102", stem: "A client with chronic heart failure (CHF) is referred for exercise therapy. What exercise parameters are safe?", options: ["Maximum effort immediately", "Low-to-moderate intensity (40-70% VO2max), frequent monitoring, avoid Valsalva, and watch for signs of decompensation", "No exercise — complete rest", "High-intensity interval training"], correctIndex: 1, rationale: "CHF exercise: low-to-moderate intensity, monitor symptoms (dyspnea, weight gain, edema), avoid Valsalva maneuver, monitor HR/BP, and stop if signs of decompensation occur.", difficulty: 2, category: "Clinical Case Scenarios", topic: "cardiac exercise" },
  { id: "pta-1103", stem: "A 75-year-old client with osteoporosis sustains a compression fracture of T12. Which exercise is contraindicated?", options: ["Walking", "Trunk flexion exercises (sit-ups, crunches, forward bending)", "Standing extension exercises", "Balance training"], correctIndex: 1, rationale: "Trunk flexion increases anterior vertebral compression forces, risking additional fractures in osteoporotic bone. Extension exercises, weight-bearing, and postural training are indicated.", difficulty: 1, category: "Clinical Case Scenarios", topic: "osteoporosis management" },
  { id: "pta-1104", stem: "A client with COPD becomes dyspneic during ambulation training. Which breathing technique should the PTA teach?", options: ["Hold breath during exertion", "Pursed-lip breathing: inhale through nose (2 counts), exhale through pursed lips (4 counts); coordinate breathing with activity", "Breathe rapidly through the mouth", "No breathing instruction needed"], correctIndex: 1, rationale: "Pursed-lip breathing creates backpressure keeping airways open, improving gas exchange and reducing air trapping. Coordinate exhalation with exertion (blow out during the hard part).", difficulty: 1, category: "Clinical Case Scenarios", topic: "pulmonary rehabilitation" },
  { id: "pta-1105", stem: "A client post-stroke is 2 weeks into rehabilitation. They have a flaccid right upper extremity. What is the priority for the affected arm?", options: ["Aggressive passive stretching", "Proper positioning to prevent subluxation, maintain ROM, and protect the shoulder", "Ignore the arm and focus on the legs", "Maximum resistance strengthening"], correctIndex: 1, rationale: "Flaccid stage: protect the shoulder from subluxation (arm support, positioning), maintain passive ROM (gentle PROM), educate about shoulder protection, and begin facilitation techniques.", difficulty: 2, category: "Clinical Case Scenarios", topic: "acute stroke management" },
  { id: "pta-1106", stem: "A 12-year-old athlete presents with knee pain at the tibial tuberosity that worsens with running and jumping. What is the likely condition?", options: ["ACL tear", "Osgood-Schlatter disease (traction apophysitis of the tibial tuberosity)", "Meniscal tear", "Patella fracture"], correctIndex: 1, rationale: "Osgood-Schlatter disease is a common adolescent condition: traction apophysitis at the tibial tuberosity from quadriceps pulling during growth. Treatment: activity modification, stretching, ice, and symptom management.", difficulty: 1, category: "Clinical Case Scenarios", topic: "pediatric knee conditions" },
  { id: "pta-1107", stem: "A client recovering from a total hip replacement (posterior approach) needs to learn how to sit in a chair. Which chair modification is needed?", options: ["Low soft chair", "Elevated firm chair or raised seat cushion to keep hip flexion below 90°", "Rocking chair", "Bean bag chair"], correctIndex: 1, rationale: "Posterior THR precaution: hip flexion <90°. An elevated, firm chair (or raised cushion) keeps the hip above the knee level, maintaining the precaution during sitting.", difficulty: 1, category: "Clinical Case Scenarios", topic: "hip replacement ADL training" },
  { id: "pta-1108", stem: "A client is being treated for lateral ankle sprain (Grade II). At 3 weeks post-injury, what is the appropriate rehabilitation focus?", options: ["Complete rest", "Progressive weight-bearing, ROM restoration, peroneal strengthening, and beginning proprioceptive training", "Return to full sport immediately", "Only ice and elevation"], correctIndex: 1, rationale: "3 weeks post-Grade II sprain: progressive WB, restore full ROM, strengthen peroneals (eversion), begin proprioceptive training (balance board), and continue modalities for pain/swelling.", difficulty: 2, category: "Clinical Case Scenarios", topic: "ankle sprain rehabilitation" },
  { id: "pta-1109", stem: "A client with a complete T4 SCI wants to be independent with wheelchair mobility. Which muscles are available for propulsion?", options: ["No muscles available", "Full upper extremity muscles including latissimus dorsi, pectorals, deltoids, biceps, triceps, and partial trunk", "Only neck muscles", "Full lower extremity muscles"], correctIndex: 1, rationale: "T4 SCI preserves full UE function and upper trunk muscles (upper abdominals). The client has excellent potential for independent wheelchair mobility, transfers, and self-care.", difficulty: 2, category: "Clinical Case Scenarios", topic: "SCI functional potential" },
  { id: "pta-1110", stem: "A PTA is developing a return-to-sport plan for a soccer player 9 months post-ACL reconstruction. Which functional tests should be performed?", options: ["Only visual assessment", "Single-leg hop tests, Y-Balance test, isokinetic strength testing (>90% limb symmetry), and sport-specific agility drills", "No testing needed", "Only treadmill walking"], correctIndex: 1, rationale: "Return-to-sport criteria post-ACL: >90% limb symmetry in hop tests, isokinetic strength, Y-Balance test, sport-specific drills, and psychological readiness. Testing occurs at 6-12 months.", difficulty: 2, category: "Clinical Case Scenarios", topic: "return-to-sport testing" },
  { id: "pta-1111", stem: "When developing a rehabilitation plan for a client post-TKR, what is the FIRST priority?", options: ["Running", "Restore knee ROM (especially extension), manage pain/edema, and achieve functional mobility for safe discharge", "Upper body strengthening", "Community ambulation"], correctIndex: 1, rationale: "Post-TKR priorities: achieve full knee extension (0°), progress flexion (90° by 2 weeks), manage pain/edema, transfer and ambulation training, and stair management for safe discharge.", difficulty: 1, category: "Rehabilitation Planning", topic: "TKR rehabilitation planning" },
  { id: "pta-1112", stem: "A client will be discharged home with stairs. What information does the PTA need for discharge planning?", options: ["Only the number of stairs", "Number of stairs, handrail availability (bilateral/unilateral), stair width, landing availability, and client's stair management ability", "Only the client's height", "Only the client's diagnosis"], correctIndex: 1, rationale: "Stair assessment for discharge: number of stairs (interior/exterior), handrail availability and sides, stair width, landing space, lighting, and the client's demonstrated stair management ability.", difficulty: 1, category: "Rehabilitation Planning", topic: "discharge stair assessment" },
  { id: "pta-1113", stem: "A client with bilateral knee OA is planning a long-term exercise program. What should the PTA recommend?", options: ["Avoid all exercise", "Low-impact aerobic exercise (walking, cycling, aquatics), quadriceps/hip strengthening, flexibility, and weight management", "Only running", "High-impact plyometrics"], correctIndex: 1, rationale: "OA exercise program: low-impact aerobic exercise, quadriceps and hip strengthening, ROM/flexibility, weight management, joint protection education, and activity modification.", difficulty: 1, category: "Rehabilitation Planning", topic: "OA exercise programming" },
  { id: "pta-1114", stem: "Which outcome measure is MOST appropriate for assessing balance in an elderly client?", options: ["Manual Muscle Test", "Berg Balance Scale (BBS) — 14-item functional balance assessment", "Visual Analog Scale", "Jamar dynamometer"], correctIndex: 1, rationale: "The BBS assesses 14 functional balance tasks on a 0-4 scale (max 56). Scores <45 indicate fall risk. It is the most widely used balance assessment for older adults.", difficulty: 1, category: "Rehabilitation Planning", topic: "balance outcome measures" },
  { id: "pta-1115", stem: "A client needs a home exercise program for chronic low back pain self-management. What should be included?", options: ["Only rest", "Core stabilization exercises, stretching (hamstrings, hip flexors), aerobic exercise, posture education, and pain management strategies", "Maximum weight lifting", "Only ice application"], correctIndex: 1, rationale: "Chronic LBP HEP: core stabilization, flexibility (hamstrings, hip flexors), regular aerobic exercise, posture/body mechanics education, self-management strategies, and gradual activity progression.", difficulty: 1, category: "Rehabilitation Planning", topic: "LBP self-management" },
  { id: "pta-1116", stem: "When planning PT for a client with progressive MS, which approach is MOST appropriate?", options: ["Only restorative exercises", "Compensatory strategies, energy conservation, adaptive equipment, aerobic conditioning avoiding overheating, and fall prevention", "Aggressive high-intensity exercise", "No exercise — rest only"], correctIndex: 1, rationale: "Progressive MS requires compensatory approaches, energy conservation, cool exercise environments (avoid Uhthoff's phenomenon), moderate aerobic conditioning, and adaptive equipment.", difficulty: 2, category: "Rehabilitation Planning", topic: "MS rehabilitation" },
  { id: "pta-1117", stem: "A client recovering from a hip fracture has osteoporosis. What exercise modifications are needed?", options: ["No modifications", "Avoid high-impact activities, emphasize weight-bearing exercise, balance training, posture correction, and fall prevention", "Only bed rest", "Maximum weight lifting"], correctIndex: 1, rationale: "Osteoporosis with hip fracture: weight-bearing exercise (promotes bone density), balance training (fall prevention), avoid excessive trunk flexion, and progressive functional mobility.", difficulty: 1, category: "Rehabilitation Planning", topic: "osteoporosis rehabilitation" },
  { id: "pta-1118", stem: "What is the recommended timeframe for short-term goals in an inpatient rehabilitation setting?", options: ["1 day", "1-2 weeks", "6 months", "1 year"], correctIndex: 1, rationale: "Inpatient rehab short-term goals typically span 1-2 weeks. They should be functional, measurable, achievable stepping stones toward long-term discharge goals.", difficulty: 1, category: "Rehabilitation Planning", topic: "goal timeframes" },
  { id: "pta-1119", stem: "A PTA is educating a client about proper body mechanics for lifting. What is the KEY instruction?", options: ["Bend at the waist, keep load far from body", "Bend at the knees, keep the load close to the body, maintain neutral spine, and avoid twisting", "Twist while lifting heavy objects", "Use only the back muscles"], correctIndex: 1, rationale: "Proper lifting: wide base, bend knees (not waist), keep load close to body, maintain neutral spine, tighten core, avoid twisting, and push/pull rather than lift when possible.", difficulty: 1, category: "Patient Education", topic: "body mechanics education" },
  { id: "pta-1120", stem: "When educating a client about their total hip replacement precautions, which visual aid is MOST effective?", options: ["Complex anatomy textbook", "Simple diagrams showing prohibited positions with daily activity examples (crossing legs, bending to tie shoes)", "Surgical video", "No visual aids"], correctIndex: 1, rationale: "Simple visual diagrams with 'do' and 'don't' daily activity examples help clients understand and remember precautions. Relate abstract concepts to concrete daily tasks.", difficulty: 1, category: "Patient Education", topic: "hip precaution education" },
  { id: "pta-1121", stem: "A client needs education on skin inspection for pressure injury prevention. What should the PTA teach?", options: ["Check skin once a month", "Daily skin inspection of bony prominences (sacrum, heels, ischial tuberosities), look for redness that doesn't blanch, and report any changes", "Skin checks are not necessary", "Only check when pain is present"], correctIndex: 1, rationale: "Daily skin inspection: check bony prominences, look for non-blanchable redness (Stage 1 pressure injury), temperature changes, and skin breakdown. Report changes immediately.", difficulty: 1, category: "Patient Education", topic: "pressure injury prevention" },
  { id: "pta-1122", stem: "Which teach-back technique verifies that a client understands their exercise program?", options: ["Ask 'Do you understand?'", "Have the client demonstrate each exercise and explain when and how often to perform them", "Give a written quiz", "Assume understanding if they nod"], correctIndex: 1, rationale: "Teach-back: the client demonstrates exercises and explains frequency/intensity/precautions. This confirms comprehension and correct technique, not just verbal agreement.", difficulty: 1, category: "Patient Education", topic: "comprehension verification" },
  { id: "pta-1123", stem: "A PTA is educating an elderly client about fall prevention at home. What is the MOST important modification?", options: ["New furniture", "Remove throw rugs, improve lighting (especially nightlights for bathroom trips), and install grab bars in the bathroom", "New paint colors", "Better curtains"], correctIndex: 1, rationale: "Home fall prevention priorities: remove trip hazards (throw rugs, cords), improve lighting (nightlights, stairway lights), install grab bars (bathroom), and maintain clear pathways.", difficulty: 1, category: "Patient Education", topic: "fall prevention education" },
  { id: "pta-1124", stem: "When educating a client with arthritis about exercise, which key message should be emphasized?", options: ["Exercise makes arthritis worse", "Regular moderate exercise reduces pain, improves function, and maintains joint health; rest worsens stiffness", "Only exercise during flare-ups", "Avoid all weight-bearing"], correctIndex: 1, rationale: "Evidence shows regular moderate exercise improves pain, function, and quality of life in arthritis. Prolonged rest leads to deconditioning and increased stiffness. Modify during flare-ups but don't stop.", difficulty: 1, category: "Patient Education", topic: "arthritis exercise education" },
  { id: "pta-1125", stem: "A client recovering from a fall reports increased fear of falling. Which education component addresses this?", options: ["Tell them to stop being afraid", "Fear of falling education: confidence-building through progressive balance training, education about modifiable risk factors, and encouraging safe activity", "Recommend avoiding all activity", "No education needed"], correctIndex: 1, rationale: "Fear of falling (post-fall syndrome) leads to activity restriction, deconditioning, and increased fall risk. Address with progressive balance training, self-efficacy building, and risk factor education.", difficulty: 2, category: "Patient Education", topic: "fear of falling" },
  { id: "pta-1126", stem: "Which age-related change affects gait patterns in elderly clients?", options: ["Increased stride length", "Decreased stride length, decreased gait speed, wider base of support, and increased double-support time", "Faster gait speed", "Narrower base of support"], correctIndex: 1, rationale: "Aging gait changes: decreased stride length, decreased gait speed, wider base, increased double-support time, decreased arm swing, and reduced trunk rotation. These adaptations increase stability.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "aging gait changes" },
  { id: "pta-1127", stem: "A geriatric client with a hip fracture has a high risk of delirium post-surgery. What can the PTA do to reduce delirium risk?", options: ["Restrict all activity", "Promote early mobilization, maintain orientation cues, ensure adequate hydration/nutrition, and establish consistent routines", "Only bed exercises", "No PT intervention affects delirium"], correctIndex: 1, rationale: "Early mobilization is one of the most effective delirium prevention strategies. Additional measures: orientation cues, consistent routines, adequate sleep, hydration, and sensory aids (glasses, hearing aids).", difficulty: 2, category: "Geriatric Rehabilitation", topic: "delirium prevention" },
  { id: "pta-1128", stem: "Which exercise program has the STRONGEST evidence for reducing falls in older adults?", options: ["Only flexibility training", "Multicomponent program: balance training, strength training (LE focus), and functional mobility exercises", "Only aerobic exercise", "Only upper body strengthening"], correctIndex: 1, rationale: "Evidence supports multicomponent fall prevention: balance exercises (tai chi, single-leg stance), lower extremity strengthening, gait training, and functional mobility practice.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "fall prevention exercise" },
  { id: "pta-1129", stem: "A 78-year-old client with dementia has difficulty following multi-step exercise instructions. Which approach is BEST?", options: ["Complex verbal instructions", "Simple one-step commands, demonstration, hand-over-hand guidance, and consistent routine with familiar cues", "Written instructions only", "Expect independent exercise compliance"], correctIndex: 1, rationale: "Dementia exercise approach: simple one-step verbal cues, visual demonstration, tactile guidance, consistent environment and routine, familiar activities, and caregiver involvement.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "dementia exercise strategies" },
  { id: "pta-1130", stem: "Which standardized assessment tool measures physical function in older adults across self-care, mobility, and social function domains?", options: ["Glasgow Coma Scale", "Late Life Function and Disability Instrument (LLFDI) or FIM", "Beck Depression Inventory", "MMSE"], correctIndex: 1, rationale: "LLFDI measures function and disability in community-dwelling older adults. FIM measures independence across motor and cognitive domains. Both track functional change over time.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "geriatric assessment" },
  { id: "pta-1131", stem: "At what age does a child typically begin walking independently?", options: ["6 months", "12-15 months", "24 months", "36 months"], correctIndex: 1, rationale: "Independent walking typically emerges at 12-15 months. By 18 months, most children walk well. Running develops by 2 years, stair climbing by 2-3 years.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "motor milestones" },
  { id: "pta-1132", stem: "A child with cerebral palsy classified as GMFCS Level III primarily uses which mobility method?", options: ["Independent walking without aids", "Walking with assistive mobility device (walker, crutches) indoors, wheelchair for longer distances", "Independent running and jumping", "Full-time power wheelchair"], correctIndex: 1, rationale: "GMFCS Level III: walks with assistive devices indoors, may use wheelchair for longer community distances. Levels I-II walk without aids; IV-V primarily use wheeled mobility.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "cerebral palsy classification" },
  { id: "pta-1133", stem: "Which developmental reflex should integrate by 6 months and, if persistent, interferes with voluntary movement?", options: ["Rooting reflex", "Asymmetric tonic neck reflex (ATNR)", "Moro reflex", "All of the above"], correctIndex: 3, rationale: "Primitive reflexes (ATNR, Moro, rooting, palmar grasp) should integrate by 4-6 months. Persistent primitive reflexes interfere with voluntary movement and indicate neurological concerns.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "primitive reflexes" },
  { id: "pta-1134", stem: "A child with spina bifida at the L3-L4 level would be expected to have which functional ability?", options: ["Full independent walking", "Community ambulation with KAFOs and crutches or forearm crutches, wheelchair for long distances", "No mobility potential", "Running and sports without aids"], correctIndex: 1, rationale: "L3-L4 spina bifida: preserved hip flexion and knee extension (quadriceps). Community ambulation with KAFOs and crutches is possible; wheelchair used for energy conservation at longer distances.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "spina bifida mobility" },
  { id: "pta-1135", stem: "Which intervention is appropriate for a child with torticollis (head tilt to one side)?", options: ["No intervention needed", "Stretching of the tight SCM, strengthening of the weak side, and positioning to encourage looking toward the restricted side", "Surgery immediately", "Only observation for 1 year"], correctIndex: 1, rationale: "Torticollis treatment: stretching the tight SCM (lateral flexion away, rotation toward the tight side), AROM strengthening, and environmental positioning to encourage looking toward the restricted side.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "torticollis management" },
  { id: "pta-1136", stem: "A client post-stroke demonstrates a hemiplegic gait pattern. Which components are characteristic?", options: ["Normal gait", "Circumduction of the affected leg, hip hiking, equinovarus foot position, and decreased arm swing on affected side", "Wide-based ataxic gait", "Festinating gait"], correctIndex: 1, rationale: "Hemiplegic gait: circumduction (swinging the stiff leg outward), hip hiking, equinovarus foot (plantarflexion/inversion), stiff knee, and absent arm swing on the affected side.", difficulty: 2, category: "Neurological Rehabilitation", topic: "hemiplegic gait" },
  { id: "pta-1137", stem: "A client with a complete C5 SCI can perform which functional activities?", options: ["Independent transfers", "Feeding with adaptive equipment (mobile arm support, universal cuff), powered wheelchair mobility, and assisted transfers", "Complete independence in all ADLs", "Ambulation with walker"], correctIndex: 1, rationale: "C5 SCI: preserves deltoid and biceps. Client can feed with adaptive equipment (MAS, universal cuff), use power wheelchair, and perform assisted transfers. Dependent for most ADLs.", difficulty: 2, category: "Neurological Rehabilitation", topic: "C5 SCI function" },
  { id: "pta-1138", stem: "Which neuroplasticity principle states that the brain changes are specific to the type of training performed?", options: ["Use it or lose it", "Specificity — training-induced changes are specific to the nature of the training experience", "Reversibility", "Overload"], correctIndex: 1, rationale: "Specificity of neuroplasticity: the brain reorganizes based on the specific demands of training. Task-specific practice (practicing the actual task) produces the most relevant neural changes.", difficulty: 2, category: "Neurological Rehabilitation", topic: "neuroplasticity principles" },
  { id: "pta-1139", stem: "A client with Parkinson's disease demonstrates rigidity during passive movement. How is this different from spasticity?", options: ["They are identical", "Rigidity is velocity-independent (constant resistance throughout range); spasticity is velocity-dependent (increases with speed)", "Rigidity only occurs in the arms", "Spasticity occurs at rest only"], correctIndex: 1, rationale: "Rigidity (basal ganglia): constant resistance throughout ROM regardless of speed (lead-pipe or cogwheel). Spasticity (UMN): velocity-dependent resistance that increases with faster movement.", difficulty: 2, category: "Neurological Rehabilitation", topic: "tone abnormalities" },
  { id: "pta-1140", stem: "Which constraint-induced movement therapy (CIMT) protocol is used for upper extremity recovery post-stroke?", options: ["Restrain the affected arm", "Restrain the unaffected arm for 90% of waking hours while intensively training the affected arm 6+ hours daily", "Only passive ROM of affected arm", "No specific protocol exists"], correctIndex: 1, rationale: "CIMT: constrain the unaffected arm (mitt/sling) for 90% of waking hours, intensive task-specific training of the affected arm 6+ hours/day for 2 weeks. Requires some baseline active wrist/finger extension.", difficulty: 2, category: "Neurological Rehabilitation", topic: "CIMT protocol" },
  { id: "pta-1141", stem: "A client post-ACL reconstruction at 4 months demonstrates quadriceps strength of 70% compared to the uninvolved side. What is the appropriate intervention?", options: ["Return to sport immediately", "Progressive quadriceps strengthening (OKC/CKC), neuromuscular training, and continue rehabilitation until >90% limb symmetry", "No further strengthening needed", "Only stretching"], correctIndex: 1, rationale: "70% limb symmetry is insufficient for sport return (>90% required). Continue progressive strengthening (CKC and OKC), add neuromuscular control training, and assess limb symmetry regularly.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "ACL strength criteria" },
  { id: "pta-1142", stem: "A client 6 weeks post-rotator cuff repair is cleared for AROM. Which exercise sequence is appropriate?", options: ["Overhead lifting immediately", "Gravity-eliminated AROM → antigravity AROM → light resistance, progressing per surgeon protocol", "Maximum resistance strengthening", "No exercise until 12 weeks"], correctIndex: 1, rationale: "Post-rotator cuff AROM progression: start gravity-eliminated (supine, table slides) → progress to antigravity (seated/standing) → light resistance as the tissue continues to heal.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "rotator cuff rehabilitation" },
  { id: "pta-1143", stem: "A client with lumbar radiculopathy has pain radiating down the posterior thigh to the lateral calf and foot. Which nerve root is likely involved?", options: ["L3", "L4", "S1", "L2"], correctIndex: 2, rationale: "S1 radiculopathy: pain radiates posteriorly down the thigh, posterior/lateral calf, to the lateral foot. Weakness in plantarflexion, diminished Achilles reflex, and lateral foot numbness.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "radiculopathy patterns" },
  { id: "pta-1144", stem: "A client with a frozen shoulder (adhesive capsulitis) is in the 'thawing' phase. What is the primary intervention?", options: ["No intervention — it will resolve spontaneously", "Progressive ROM exercises (stretching), joint mobilization, and functional activity integration as motion returns", "Aggressive manipulation under anesthesia immediately", "Only pain medication"], correctIndex: 1, rationale: "The thawing phase (gradual improvement): progressive ROM exercises, joint mobilization to restore motion, strengthening as ROM improves, and integration of functional activities.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "frozen shoulder rehabilitation" },
  { id: "pta-1145", stem: "A client post-total knee replacement has persistent knee flexion contracture of 10°. What is the appropriate intervention?", options: ["Accept the contracture", "Low-load prolonged stretch (prone hang, towel extension stretch), heel props, and continuous passive extension", "Aggressive passive manipulation", "No intervention needed"], correctIndex: 1, rationale: "Post-TKR flexion contracture requires low-load prolonged stretching: prone hang, heel props (towel under ankle with weight), and sustained extension stretching to restore full extension (0°).", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "TKR contracture management" },
];
